#!/bin/bash
sed -i '/  return (/i \  \/\/ Shortcut to open new application form (Ctrl+N \/ Cmd+N)\n  useEffect(() => {\n    const handleKeyDown = (e: KeyboardEvent) => {\n      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === '\''n'\'') {\n        e.preventDefault();\n        \n        setName('\'\');\n        setTcNo('\'\');\n        setPhone('\'\');\n        setEmail('\'\');\n        setCategory('\''Lise'\'');\n        setAddress('\'\');\n        setAllergies('\'\');\n        setChronicDiseases('\'\');\n        setMedications('\'\');\n        setHealthNote('\'\');\n        setHeight('\'\');\n        setWeight('\'\');\n        setKvkkChecked(false);\n        setConsentChecked(false);\n        \n        setConvoyName('\'\');\n        setLeaderName('\'\');\n        setLeaderTc('\'\');\n        setLeaderPhone('\'\');\n        setLeaderEmail('\'\');\n        setLeaderAddress('\'\');\n        setLeaderHeight('\'\');\n        setLeaderWeight('\'\');\n        setLeaderAllergies('\'\');\n        setLeaderChronicDiseases('\'\');\n        setLeaderMedications('\'\');\n        setLeaderHealthNote('\'\');\n        setConvoyMembers([{\n          name: '\'\',\n          tcNo: '\'\',\n          birthDate: '\''2012-05-15'\'',\n          gender: '\''Erkek'\'',\n          category: '\''Lise'\'',\n          duty: '\''Katılımcı'\'',\n          height: '\'\',\n          weight: '\'\',\n          allergies: '\'\',\n          chronicDiseases: '\'\',\n          medications: '\'\',\n          healthNote: '\'\',\n          autoAllocate: true,\n          preferredBungalowId: '\'\',\n          preferredBedNumber: 0\n        }]);\n\n        if (onChangeSubView) {\n          onChangeSubView('\''form'\'');\n        }\n      }\n    };\n    window.addEventListener('\''keydown'\'', handleKeyDown);\n    return () => window.removeEventListener('\''keydown'\'', handleKeyDown);\n  }, [onChangeSubView]);\n' src/components/RegistrationView.tsx
